        public void InitAtrEvent()
        {
            UGUITriggerProxy triggerProxy = modepos.GetComponent<UGUITriggerProxy>();
            uIIntroduction ??= UIComponent.Instance.VisibleUI(UIType.UIIntroduction).GetComponent<UIIntroductionComponent>();
            triggerProxy.OnPointerClickEvent = () =>
            {
                ShowAtr();
            };
        }
        public void ShowAtr()
        {
            uIIntroduction.GetAllAtrs(knapsackDataItem);
            uIIntroduction.AddDiyAtr(diratr);
            uIIntroduction.ShowAtrs();
            uIIntroduction.Introcontent.transform.GetChild(1).gameObject.SetActive(false);
            uIIntroduction.Introcontent.GetComponent<Image>().color = new Color(255, 255, 255, 0);
                var pos = modepos.position;
                uIIntroduction.SetPos(pos +=new Vector3(9,-1,0), 1);

            if (items.transform.GetChild(1).GetChild(0).childCount == 0)
            {
                var itemobj = ResourcesComponent.Instance.LoadGameObject("Gemstone_linghunbaoshi".StringToAB(), "Gemstone_linghunbaoshi");
                itemobj.SetLayer(LayerNames.UI);
                itemobj.transform.localScale = Vector3.one;
                //if (BigIndex == 5)
                //{
                //    itemobj.transform.localScale = Vector3.one;
                //    itemobj.transform.localScale = Vector3.one * 0.5f;
                //}
                // itemobj.transform.localScale = Vector3.one;
                itemobj.transform.SetParent(items.transform.GetChild(1).GetChild(0).transform);
                itemobj.transform.localPosition = Vector3.forward * -50;
            }
            if (items.transform.GetChild(2).GetChild(0).childCount == 0)
            {
                var itemobj = ResourcesComponent.Instance.LoadGameObject("Gemstone_zhufubaoshi".StringToAB(), "Gemstone_zhufubaoshi");
                itemobj.SetLayer(LayerNames.UI);
                itemobj.transform.localScale = Vector3.one;
                //if (BigIndex == 5)
                //{
                //    itemobj.transform.localScale = Vector3.one;
                //    itemobj.transform.localScale = Vector3.one * 0.5f;
                //}
                // itemobj.transform.localScale = Vector3.one;
                itemobj.transform.SetParent(items.transform.GetChild(2).GetChild(0));
                itemobj.transform.localPosition = Vector3.forward * -50;
            }
        }

        private int GetDefaultDisplayIndex()
        {
            var role = UnitEntityComponent.Instance?.LocalRole;
            if (role == null)
            {
                return 1;
            }

            if (role.MaxMonthluCardTimeSpan.TotalSeconds > 0 || role.MinMonthluCardTimeSpan.TotalSeconds > 0)
            {
                return 1;
            }

            for (int index = 1; index <= 5; ++index)
            {
                if ((role.RechargeStates & (1 << index)) != (1 << index))
                {
                    return index;
                }
            }

            return 1;
        }

        public void ShowInitialTab()
        {
            int initialIndex = GetDefaultDisplayIndex();
            BigIndex = initialIndex;
            ChangeItems(initialIndex);

            if (togs != null && initialIndex - 1 >= 0 && initialIndex - 1 < togs.childCount)
            {
                Toggle toggle = togs.GetChild(initialIndex - 1).GetComponent<Toggle>();
                toggle?.SetIsOnWithoutNotify(true);
            }
        }


        public void Init_TopUpTogs()
