        public void ChangeItems(int index)
        {
            string curMountResName = string.Empty;
            string curMounName = string.Empty;
            int yuanbaoCount = 0;

            items.GetChild(1).gameObject.SetActive(false);
            items.GetChild(2).gameObject.SetActive(false);
            Log.DebugBrown("UIFirstCharge ChangeItems index=" + index);

            switch (index)
            {
                case 1:
                    curMountResName = "Other_yueka";
                    curMounName = "\u6708\u5361";
                    yuanbaoCount = 10;
                    CurReceivetype = 1;
                    configID = 320168;
                    PlayerShopQuota = (int)E_PlayerShopQuotaType.FirstTopUp;
                    break;
                case 2:
                    curMountResName = "Guard_ShouHuTianShi";
                    curMounName = "\u5b88\u62a4\u5929\u4f7f";
                    yuanbaoCount = 20;
                    CurReceivetype = 2;
                    configID = 300001;
                    PlayerShopQuota = (int)E_PlayerShopQuotaType.SecondTopUp;
                    break;
                case 3:
                    curMountResName = "Guard_XiaoEMo";
                    curMounName = "\u5c0f\u6076\u9b54";
                    yuanbaoCount = 20;
                    CurReceivetype = 3;
                    configID = 300002;
                    PlayerShopQuota = (int)E_PlayerShopQuotaType.ThirdTopUp;
                    break;
                case 4:
                {
                    var itemRes = GetItemResName();
                    curMountResName = itemRes.resName;
                    curMounName = $"{itemRes.name} +7";
                    yuanbaoCount = 36;
                    CurReceivetype = 4;
                    configID = itemRes.configID;
                    PlayerShopQuota = (int)E_PlayerShopQuotaType.FourthlyTopUp;
                    items.GetChild(1).gameObject.SetActive(true);
                    break;
                }
                case 5:
                {
                    var itemRes = GetItemWinResName();
                    curMountResName = itemRes.resName;
                    curMounName = itemRes.name;
                    yuanbaoCount = 68;
                    CurReceivetype = 5;
                    configID = itemRes.configID;
                    PlayerShopQuota = (int)E_PlayerShopQuotaType.FifthTopUp;
                    items.GetChild(2).gameObject.SetActive(true);
                    break;
                }
                default:
                    break;
            }

            SetknapsackDataItemAtr(configID);
            ShowAtr();
            rmb = yuanbaoCount;

            info.text = GetPurchaseInfoText(index, yuanbaoCount);
            RefreshTopUpButtonState(index);

            if (modepos.childCount != 0)
            {
                for (int j = 0, length = modepos.childCount; j < length; j++)
                {
                    ResourcesComponent.Instance.DestoryGameObjectImmediate(modepos.GetChild(j).gameObject, modepos.GetChild(j).gameObject.name.StringToAB());
                }
            }

            modeName.text = string.Empty;
            if (string.IsNullOrEmpty(curMountResName) == false)
            {
                Log.DebugBrown("curMountResName.StringToAB()" + curMountResName.StringToAB() + ":::" + curMountResName);
                var itemobj = ResourcesComponent.Instance.LoadGameObject(curMountResName.StringToAB(), curMountResName);
                itemobj.SetLayer(LayerNames.UI);
                itemobj.transform.localScale = BigIndex == 5 ? Vector3.one * 0.5f : Vector3.one;
                itemobj.transform.SetParent(modepos);
                itemobj.transform.localPosition = Vector3.forward * -50;
                modeName.text = curMounName;
            }

            if (yuanbaoCount != 0)
            {
                var item = items.GetChild(0);
                item.GetComponentInChildren<Text>().text = yuanbaoCount.ToString();
                item.gameObject.SetActive(true);
            }
            else
            {
                items.GetChild(0).gameObject.SetActive(false);
            }

