        private void RefreshTopUpButtonState(int index)
        {
            TopUpBtn.transform.GetComponentInChildren<Text>().text = "\u8d2d\u4e70";
            TopUpBtn.interactable = true;
        }

        private bool HasPurchasedTopUp(int index)
        {
            var role = UnitEntityComponent.Instance?.LocalRole;
            if (role == null)
            {
                return false;
            }

            int deviationValue = GetDeviationValueByIndex(index);
            if (deviationValue == 0)
            {
                return false;
            }

            if (TryGetRechargeRecord(role.RechargeRecord, out Dictionary<int, int> records) &&
                records.ContainsKey(deviationValue))
            {
                return true;
            }

            return (role.RechargeStates & deviationValue) == deviationValue;
        }

        private void MarkTopUpPurchased(int index)
        {
            var role = UnitEntityComponent.Instance?.LocalRole;
            if (role == null)
            {
                return;
            }

            int deviationValue = GetDeviationValueByIndex(index);
            if (deviationValue == 0)
            {
                return;
            }

            if (!TryGetRechargeRecord(role.RechargeRecord, out Dictionary<int, int> records))
            {
                records = new Dictionary<int, int>();
            }

            if (!records.ContainsKey(deviationValue))
            {
                records[deviationValue] = GetMoneyByIndex(index);
                role.RechargeRecord = BuildRechargeRecord(records);
            }

            role.RechargeStates |= deviationValue;
        }

        private static int GetDeviationValueByIndex(int index)
        {
            switch (index)
            {
                case 1:
                    return 1 << 1;
                case 2:
                    return 1 << 2;
                case 3:
                    return 1 << 3;
                case 4:
                    return 1 << 4;
                case 5:
                    return 1 << 5;
                default:
                    return 0;
            }
        }

        private static bool TryGetRechargeRecord(string rechargeRecord, out Dictionary<int, int> records)
        {
            records = new Dictionary<int, int>();
            if (string.IsNullOrWhiteSpace(rechargeRecord))
            {
                return false;
            }

            try
            {
                string trimmed = rechargeRecord.Trim();
                if (trimmed.Length < 2 || trimmed[0] != '{' || trimmed[trimmed.Length - 1] != '}')
                {
                    return false;
                }

                string content = trimmed.Substring(1, trimmed.Length - 2).Trim();
                if (string.IsNullOrWhiteSpace(content))
                {
                    return true;
                }

                string[] entries = content.Split(',');
                for (int i = 0; i < entries.Length; i++)
                {
                    string entry = entries[i];
                    if (string.IsNullOrWhiteSpace(entry))
                    {
                        continue;
                    }

                    string[] kv = entry.Split(':');
                    if (kv.Length != 2)
                    {
                        return false;
                    }

                    string keyText = kv[0].Trim().Trim('"');
                    string valueText = kv[1].Trim().Trim('"');
                    if (!int.TryParse(keyText, out int key) || !int.TryParse(valueText, out int value))
                    {
                        return false;
                    }

                    records[key] = value;
                }

                return true;
            }
            catch (Exception ex)
            {
                Log.Warning($"UIFirstCharge parse RechargeRecord failed: {ex.Message}");
                records = new Dictionary<int, int>();
                return false;
            }
        }

        private static string BuildRechargeRecord(Dictionary<int, int> records)
        {
            if (records == null || records.Count == 0)
            {
                return "{}";
            }

            StringBuilder builder = new StringBuilder();
            builder.Append('{');
            bool first = true;
            foreach (var item in records)
            {
                if (!first)
                {
                    builder.Append(',');
                }

                first = false;
                builder.Append('"');
                builder.Append(item.Key);
                builder.Append('"');
                builder.Append(':');
                builder.Append(item.Value);
            }

            builder.Append('}');
            return builder.ToString();
        }

