        private string GetPurchaseInfoText(int index, int yuanbaoCount)
        {
            string baseText = $"\u82b1\u8d39<size=50><color=red>{yuanbaoCount}\u9b54\u6676</color></size> \u5373\u53ef\u8d2d\u4e70\u793c\u5305";
            if (index != 1)
            {
                return baseText;
            }

            var role = UnitEntityComponent.Instance?.LocalRole;
            if (role == null)
            {
                return baseText;
            }

            TimeSpan remain = role.MaxMonthluCardTimeSpan.TotalSeconds > 0
                ? role.MaxMonthluCardTimeSpan
                : role.MinMonthluCardTimeSpan;

            if (remain.TotalSeconds <= 0)
            {
                return baseText + "\n<size=28><color=#d9c792>\u8d2d\u4e70\u540e\u53ef\u6fc0\u6d3b30\u5929\u6708\u5361\u7279\u6743</color></size>";
            }

            string remainText = FormatMonthCardRemain(remain);
            string expireText = DateTime.Now.Add(remain).ToString("yyyy-MM-dd HH:mm");
            return $"{baseText}\n<size=28><color=#9ce86b>\u5f53\u524d\u5269\u4f59\uff1a{remainText}</color></size>\n<size=28><color=#d9c792>\u5230\u671f\u65f6\u95f4\uff1a{expireText}</color></size>";
        }

        private static string FormatMonthCardRemain(TimeSpan remain)
        {
            if (remain.TotalSeconds <= 0)
            {
                return "\u5df2\u5230\u671f";
            }

            if (remain.Days > 0)
            {
                return $"{remain.Days}\u5929{remain.Hours}\u5c0f\u65f6{remain.Minutes}\u5206\u949f";
            }

            if (remain.Hours > 0)
            {
                return $"{remain.Hours}\u5c0f\u65f6{remain.Minutes}\u5206\u949f";
            }

            return $"{remain.Minutes}\u5206\u949f{remain.Seconds}\u79d2";
        }

        public void OnKeyGetAward()
        {
            int money = GetNeedCZMoney();
            TopUp((int)E_PlayerShopQuotaType.OneTimeRecharge).Coroutine();
        }

        public int GetNeedCZMoney()
        {
            int money = 0;
            Transform togs = collector.GetGameObject("Togs").transform;
            for (int i = 0, length = togs.childCount; i < length; i++)
            {
                int index = i + 1;
                int count = GetMoneyByIndex(index);
                money += count;
            }
            return money;
        }

        public int GetMoneyByIndex(int index)
        {
            switch (index)
            {
                case 1:
                    return 10;
                case 2:
                    return 20;
                case 3:
                    return 20;
                case 4:
                    return 36;
                case 5:
                    return 68;
                default:
                    return 0;
            }
        }

        public async ETTask OnTopUpButtonClick()
        {
            await ReceiveTopUpReward();
        }

        private async ETTask ReceiveTopUpReward()
        {
            G2C_ShopMallReceiveResponse response = (G2C_ShopMallReceiveResponse)await SessionComponent.Instance.Session.Call(new C2G_ShopMallReceiveRequest
            {
                Type = this.PlayerShopQuota
            });

            if (response.Error != 0)
            {
                string hint = string.IsNullOrWhiteSpace(response.Message)
                    ? response.Error.GetTipInfo()
                    : response.Message;
                UIComponent.Instance.VisibleUI(UIType.UIHint, hint);
                return;
            }

            ChangeItems(BigIndex);
            UIComponent.Instance.VisibleUI(UIType.UIHint, "\u8d2d\u4e70\u6210\u529f");
        }

        public async ETVoid TopUp(int topuprmb)
        {
            await ETTask.CompletedTask;
            TopUpComponent.Instance.TopUp(topuprmb).Coroutine();
        }

